pub struct Clearinghouse { _data: [u64; 2700] }

pub fn compute_adl_ranking_score(
    clearinghouse_ptr: &Clearinghouse,
    market_idx: usize,
) -> (u64, i64, i64) {
    // BB 0/2/4: bounds-check market_idx against the markets vec length
    // (clearinghouse[0xe8]) and load the entry row at clearinghouse[0xe0] +
    // market_idx*0x60. Returns oracle/entry/result fields for the market.
    let entry_notional_3 = clearinghouse_ptr._data[market_idx] as i64;
    let oracle_price_qty = clearinghouse_ptr._data[market_idx + 1];
    let result_1 = clearinghouse_ptr._data[market_idx + 2] as i64;
    (oracle_price_qty, entry_notional_3, result_1)
}

